                            <div className="ppe-row"><span className="ppe-key">Product Name</span><span className="ppe-val">{product.productName}</span></div>
                            <div className="ppe-row"><span className="ppe-key">Current Purchase Price</span><span className="ppe-val">Γé╣{product.purchasePrice}</span></div>
